require 'html_to_markdown'
require 'json'

RSpec.describe 'metadata' do
  it "metadata_author_meta: Extract author from <meta name='author'> tag" do
    result = HtmlToMarkdown.convert('<html><head><title>Page</title><meta name="author" content="Jane Doe"></head><body><p>Content</p></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.document.author.to_s.strip).to eq('Jane Doe'.strip)

  end

  it "metadata_canonical_url: Extract canonical URL from <link rel='canonical'> tag" do
    result = HtmlToMarkdown.convert('<html><head><title>Page</title><link rel="canonical" href="https://example.com/canonical-page"></head><body><p>Content</p></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.document.canonical_url.to_s.strip).to eq('https://example.com/canonical-page'.strip)

  end

  it "metadata_description_meta: Extract description from <meta name='description'> tag" do
    result = HtmlToMarkdown.convert('<html><head><title>Page</title><meta name="description" content="This is the page description."></head><body><p>Content</p></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.document.description.to_s.strip).to eq('This is the page description.'.strip)

  end

  it 'metadata_dublin_core: Extract Dublin Core metadata tags' do
    result = HtmlToMarkdown.convert('<html><head><title>Scholarly Work</title><meta name="DC.title" content="Principles of Knowledge Management"><meta name="DC.creator" content="Dr. Alice Johnson"><meta name="DC.date" content="2023-06-15"><meta name="DC.subject" content="Knowledge Management"><meta name="DC.publisher" content="Academic Press"></head><body><p>This is a scholarly article.</p></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('scholarly article')

  end

  it 'metadata_extract_all_images: Extract all images from a document into metadata' do
    result = HtmlToMarkdown.convert('<html><head><title>Gallery</title></head><body><img src="https://example.com/photo1.jpg" alt="Photo 1"><img src="https://example.com/photo2.png" alt="Photo 2"><img src="/local/image.webp" alt="Local image"></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.images.length).to be >= 2

  end

  it 'metadata_extract_all_links: Extract all links from a document into metadata' do
    result = HtmlToMarkdown.convert('<html><head><title>Links Page</title></head><body><p>Visit <a href="https://example.com">Example</a> or <a href="https://docs.example.com">Docs</a>.</p><p>Also see <a href="/relative/path">relative link</a> and <a href="mailto:hello@example.com">email us</a>.</p></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.links.length).to be >= 2

  end

  it 'metadata_headers_hierarchy: Extract heading hierarchy from document into metadata' do
    result = HtmlToMarkdown.convert('<html><head><title>Docs</title></head><body><h1>Introduction</h1><h2>Getting Started</h2><h3>Installation</h3><h3>Configuration</h3><h2>Advanced Usage</h2><h3>Custom Options</h3></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.headers.length).to be >= 5

  end

