  it 'metadata_microdata_schema_article: Extract schema.org microdata for Article' do
    result = HtmlToMarkdown.convert('<html><head><title>Article</title></head><body><article itemscope itemtype="https://schema.org/Article"><h1 itemprop="headline">Breaking News Today</h1><span itemprop="author">Jane Reporter</span><span itemprop="datePublished">2024-04-22</span><div itemprop="articleBody"><p>The article content goes here with important information about the breaking news story.</p></div></article></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Breaking News Today')
    expect(result.content.to_s).to include('Jane Reporter')
    expect(result.content.to_s).to include('important information')

  end

  it 'metadata_microdata_schema_breadcrumb: Extract schema.org breadcrumb navigation microdata' do
    result = HtmlToMarkdown.convert('<html><head><title>Navigation</title></head><body><nav itemscope itemtype="https://schema.org/BreadcrumbList"><span itemprop="itemListElement" itemscope itemtype="https://schema.org/ListItem"><a itemprop="item" href="https://example.com"><span itemprop="name">Home</span></a></span><span itemprop="itemListElement" itemscope itemtype="https://schema.org/ListItem"><a itemprop="item" href="https://example.com/products"><span itemprop="name">Products</span></a></span><span itemprop="itemListElement" itemscope itemtype="https://schema.org/ListItem"><span itemprop="name">Current Page</span></span></nav></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true, preprocessing: { 'remove_navigation' => false }))
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Home')
    expect(result.content.to_s).to include('Products')
    expect(result.content.to_s).to include('Current Page')

  end

  it 'metadata_microdata_schema_organization: Extract schema.org microdata for Organization' do
    result = HtmlToMarkdown.convert('<html><head><title>Company</title></head><body><div itemscope itemtype="https://schema.org/Organization"><span itemprop="name">Acme Corp</span><span itemprop="foundingDate">2020</span><span itemprop="url">https://acmecorp.example.com</span><span itemprop="logo">https://acmecorp.example.com/logo.png</span></div></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Acme Corp')
    expect(result.content.to_s).to include('2020')

  end

  it 'metadata_microdata_schema_person: Extract schema.org microdata for Person' do
    result = HtmlToMarkdown.convert('<html><head><title>Contact</title></head><body><div itemscope itemtype="https://schema.org/Person"><span itemprop="name">John Smith</span><span itemprop="email">john@example.com</span><span itemprop="telephone">+1-555-0100</span></div></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
