    expect(result.content.to_s).to include('right-to-left text')

  end

  it 'metadata_title_tag: Extract title from <title> tag' do
    result = HtmlToMarkdown.convert('<html><head><title>My Page</title></head><body><p>Content</p></body></html>', HtmlToMarkdownRs::ConversionOptions.new(extract_metadata: true))
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.document.title.to_s.strip).to eq('My Page'.strip)

  end

  it 'og_basic_tags: Extract og:title, og:description, and og:image from Open Graph meta tags' do
    result = HtmlToMarkdown.convert('<html><head><title>Fallback Title</title><meta property="og:title" content="OG Title"><meta property="og:description" content="OG description text."><meta property="og:image" content="https://example.com/image.jpg"></head><body><p>Content</p></body></html>')
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.document.open_graph["title"].to_s.strip).to eq('OG Title'.strip)
    expect(result.metadata.document.open_graph["description"].to_s.strip).to eq('OG description text.'.strip)
    expect(result.metadata.document.open_graph["image"].to_s.strip).to eq('https://example.com/image.jpg'.strip)

  end

  it 'og_multiple_tags: Extract multiple Open Graph tags including type, url, and site_name' do
    result = HtmlToMarkdown.convert('<html><head><meta property="og:title" content="Article Title"><meta property="og:type" content="article"><meta property="og:url" content="https://example.com/article"><meta property="og:site_name" content="Example Site"><meta property="og:description" content="An interesting article."><meta property="og:image" content="https://example.com/article.jpg"></head><body><article><p>Article content here.</p></article></body></html>')
    expect(result.content.to_s).not_to be_empty
    expect(result.metadata.document.open_graph["title"].to_s.strip).to eq('Article Title'.strip)
    expect(result.metadata.document.open_graph["type"].to_s.strip).to eq('article'.strip)
    expect(result.metadata.document.open_graph["url"].to_s.strip).to eq('https://example.com/article'.strip)
    expect(result.metadata.document.open_graph["site_name"].to_s.strip).to eq('Example Site'.strip)

  end

  it 'structured_data_json_ld: JSON-LD script tag is stripped from output (security) but metadata may be extracted' do
    result = HtmlToMarkdown.convert('<html><head><title>Article</title><script type="application/ld+json">{"@context":"https://schema.org","@type":"Article","headline":"My Article","author":{"@type":"Person","name":"Jane Doe"},"datePublished":"2024-01-15"}</script></head><body><h1>My Article</h1><p>Article body text.</p></body></html>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('My Article')

  end

  it 'structured_data_multiple_json_ld: Multiple JSON-LD blocks are all stripped from output' do
    result = HtmlToMarkdown.convert('<html><head><title>Shop Page</title><script type="application/ld+json">{"@context":"https://schema.org","@type":"Product","name":"Widget","price":"9.99"}</script><script type="application/ld+json">{"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[{"@type":"ListItem","position":1,"name":"Home"}]}</script></head><body><h1>Widget</h1><p>A great widget for all purposes.</p></body></html>')
    expect(result.content.to_s).not_to be_empty
